import React from 'react';
import styled from 'styled-components';
import Footer from '../components/Footer';

const GalleryContainer = styled.div`
  min-height: 100vh;
  background: #000;
  padding-top: 80px;
`;

const GallerySection = styled.section`
  padding: 100px 10%;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const GalleryGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 20px;
  padding: 20px;

  img {
    width: 100%;
    height: 300px;
    object-fit: cover;
    border-radius: 10px;
    transition: transform 0.3s ease;
    cursor: pointer;

    &:hover {
      transform: scale(1.05);
    }
  }
`;

const Gallery = () => {
  const images = [
    'IMG_0317.jpg',
    'IMG_0325.jpg',
    'IMG_0331.jpg',
    'IMG_0341.jpg',
    'IMG_0358.jpg',
    'IMG_5760.jpeg',
    'IMG_5766.JPG',
    'IMG_5773.JPG',
    'IMG_5780.JPG',
    'IMG_0314.jpg',
    'IMG_0322.jpg',
    'IMG_0326.jpg',
    'IMG_0333.jpg',
    'IMG_0338.jpg',
    'IMG_0352.jpg'
  ];

  return (
    <GalleryPage>
      <GallerySection>
        <Header>
          <h2 data-aos="fade-up">Gallery</h2>
        </Header>
        <GalleryGrid>
          {images.map((image, index) => (
            <img
              key={index}
              src={require(`../assets/${image}`)}
              alt={`Gallery image ${index + 1}`}
              data-aos="fade-up"
              data-aos-delay={100 * (index % 4)}
            />
          ))}
        </GalleryGrid>
      </GallerySection>
      <Footer />
    </GalleryPage>
  );
};

export default GalleryPage;
